import socket
import struct

ETHERTYPES = {
    'ipv4': 0x0800, 'arp': 0x0806, 'ipv6': 0x86DD, '8021q': 0x8100,
    'ipx': 0x8137, 'eapol': 0x888E, 'lldp': 0x88CC, 'mpls': 0x8847,
    'pppoe_disc': 0x8863, 'pppoe_sess': 0x8864
}

def mac_to_bytes(mac_str):
    mac_str = mac_str.replace('-', ':').lower()
    return bytes(int(b, 16) for b in mac_str.split(':'))

def bytes_to_mac(mac_bytes):
    return ':'.join('%02x' % b for b in mac_bytes)

def build_ethernet(dst_mac, src_mac, ethertype, payload):
    if isinstance(dst_mac, str):
        dst_mac = mac_to_bytes(dst_mac)
    if isinstance(src_mac, str):
        src_mac = mac_to_bytes(src_mac)
    if isinstance(ethertype, str):
        ethertype = ETHERTYPES.get(ethertype.lower(), 0x0800)
    frame = dst_mac + src_mac + struct.pack('!H', ethertype) + payload
    return frame

def build_vlan_frame(dst_mac, src_mac, vlan_id, priority, ethertype, payload):
    if isinstance(dst_mac, str):
        dst_mac = mac_to_bytes(dst_mac)
    if isinstance(src_mac, str):
        src_mac = mac_to_bytes(src_mac)
    if isinstance(ethertype, str):
        ethertype = ETHERTYPES.get(ethertype.lower(), 0x0800)
    tci = ((priority & 0x07) << 13) | (vlan_id & 0x0FFF)
    frame = dst_mac + src_mac
    frame += struct.pack('!H', 0x8100)
    frame += struct.pack('!H', tci)
    frame += struct.pack('!H', ethertype)
    frame += payload
    return frame

def parse_ethernet(frame):
    if len(frame) < 14:
        return None
    dst_mac = bytes_to_mac(frame[0:6])
    src_mac = bytes_to_mac(frame[6:12])
    ethertype = struct.unpack('!H', frame[12:14])[0]
    payload_offset = 14
    vlan_id = None
    if ethertype == 0x8100:
        tci = struct.unpack('!H', frame[14:16])[0]
        vlan_id = tci & 0x0FFF
        ethertype = struct.unpack('!H', frame[16:18])[0]
        payload_offset = 18
    return {'dst_mac': dst_mac, 'src_mac': src_mac, 'ethertype': hex(ethertype),
            'vlan_id': vlan_id, 'payload': frame[payload_offset:]}

def send_raw_frame(interface, frame):
    s = socket.socket(socket.AF_PACKET, socket.SOCK_RAW, socket.htons(0x0003))
    s.bind((interface, 0))
    s.send(frame)
    s.close()

